import React from 'react';

function App() {
  return (
    <div>
      {/* Navigation Menu */}
      <nav style={{ padding: '10px', backgroundColor: '#333', color: '#fff' }}>
        <a href="#home" style={{ margin: '10px', color: '#fff', textDecoration: 'none' }}>Home</a>
        <a href="#about" style={{ margin: '10px', color: '#fff', textDecoration: 'none' }}>About</a>
        <a href="#contact" style={{ margin: '10px', color: '#fff', textDecoration: 'none' }}>Contact</a>
      </nav>

      {/* Home Section */}
      <section id="home" style={{ padding: '50px', textAlign: 'center' }}>
        <h1>Hello, Tayyab!</h1>
        <p>My first React app is running!</p>
        <button onClick={() => alert('You clicked me!')}>Click Me</button>
      </section>

      {/* About Section */}
      <section id="about" style={{ padding: '50px', textAlign: 'center', backgroundColor: '#f0f0f0' }}>
        <h1>About Section</h1>
        <p>This is a simple React navigation example.</p>
      </section>

      {/* Contact Section */}
      <section id="contact" style={{ padding: '50px', textAlign: 'center' }}>
        <h1>Contact Section</h1>
        <p>Get in touch!</p>
      </section>
    </div>
  );
}

export default App;
